import{_ as t,o,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"39. Introduction Of Revised Pathology Collector Structure","description":"","frontmatter":{"title":"39. Introduction Of Revised Pathology Collector Structure","eba":"Health Allied & Managers Admin 2021-2025","topics":["classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/39-introduction-of-revised-pathology-collector-structure.md","filePath":"ebas/has-managers-admin/health-allied-services/classification-staffing/39-introduction-of-revised-pathology-collector-structure.md"}'),l={name:"ebas/has-managers-admin/health-allied-services/classification-staffing/39-introduction-of-revised-pathology-collector-structure.md"};function i(s,e,n,c,h,d){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_39-introduction-of-revised-pathology-collector-structure" tabindex="-1">39. Introduction Of Revised Pathology Collector Structure <a class="header-anchor" href="#_39-introduction-of-revised-pathology-collector-structure" aria-label="Permalink to &quot;39. Introduction Of Revised Pathology Collector Structure&quot;">​</a></h1><p><strong>39.1</strong> From FFPPOA 1 July 2021, Employees classified as Pathology Collectors will translate to the new Pathology Collector classification structure as follows:</p><p>Current classification New classification Pathology Collector in Training Pathology Collector Grade 1</p><p>Pathology Collector Grade 1 Pathology Collector Grade 2 Pathology Collector (Mobile Collector) Pathology Collector Grade 3 Pathology Collector Grade 2 Pathology Collector Grade 4</p><p><strong>39.2</strong> Within 3 months of the commencement of the Agreement, the Employers will review the existing Employees classified as Pathology Collector and confirm in writing to those Employees:</p><p><strong>(a)</strong> to which classification they have translated, effective from FFPPOA 1 July</p><p><strong>(b)</strong> whether their duties change as a result of the translation</p><p><strong>(c)</strong> back payment of wages (if any) effective from FFPPOA 1 July 2021</p><p><strong>39.3</strong> Where an Employee disagrees with this re-classification, in the first instance the dispute will be dealt with by the AIC. If the matter remains in dispute, it will be dealt with in accordance with Section 1 <a href="/eba/ebas/has-managers-admin/health-allied-services/allowances/17-reimbursement-of-expenses-dhsv.html">clause 17</a> (Dispute Resolution Procedure).</p>',9)])])}const g=t(l,[["render",i]]);export{u as __pageData,g as default};
